proof_block:
// Bind the spec call to a single name so z3 only needs to instantiate the
// `get_iommu_table_by_ioid(ioid).unwrap().mapping_4k()` term once for both
// r1's and r2's ensures, rather than once per occurrence.
let m = self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k();
let contains_va = m.dom().contains(va);

// Lift the antecedent of the synthetic ensures into a single local bool, then
// case-split on it: inside `if h { ... }` every conjunct of the antecedent
// is a hypothesis, so the helper lemma's `requires` are satisfied and the
// lemma yields `det_resolve_iommu_table_mapping_equal(r1, r2)` — exactly the
// consequent of the synthetic ensures' implication.
let h: bool = {
    &&& (contains_va == (r1 is Some))
    &&& (r1 is Some ==> contains_va
            && m[va] == page_entry_to_map_entry(&r1.unwrap()))
    &&& (contains_va == (r2 is Some))
    &&& (r2 is Some ==> contains_va
            && m[va] == page_entry_to_map_entry(&r2.unwrap()))
};

if h {
    lemma_resolve_iommu_table_mapping_det_equal(self_, ioid, va, r1, r2);
    assert(det_resolve_iommu_table_mapping_equal(r1, r2));
}
// After the `if h { ... }`, Verus has `h ==> det_resolve_iommu_table_mapping_equal(r1, r2)`.
// Since `h` is structurally identical to the antecedent of the synthetic
// ensures, this discharges the implication.

helper_lemmas:
// Functional-uniqueness lemma for the resolve_iommu_table_mapping
// determinism check.
//
// The synthetic det_<f> ensures has shape
//     H(r1) && H(r2) ==> det_equal(r1, r2)
// where H(r) is the original ensures applied to a candidate result.
// Inside the proof body, H(r1) and H(r2) are *not* hypotheses — they are
// only the antecedent of the implication. Lifting the antecedent into this
// lemma's `requires` turns each conjunct into a real hypothesis available
// to the proof body.
//
// The closed `view()` of PageEntry returns `PageEntryView { addr, perm }`,
// i.e. it is literally the projection (addr, perm). To prove view equality
// we therefore have to prove `addr` equality and *full* `perm` equality.
// `page_entry_to_map_entry` only projects {addr, perm.write, perm.execute_disable},
// so the three remaining perm bits {present, ps, user} cannot be pinned by
// the mapping_4k hypothesis alone. We assemble what can be derived from the
// projection equality, then bridge to view equality by extensional struct
// equality (`=~=`) on PageEntryView — Verus reduces that to per-field
// equality recursively. Each step below is checked by Verus.
proof fn lemma_resolve_iommu_table_mapping_det_equal(
    self_: &MemoryManager,
    ioid: IOid,
    va: VAddr,
    r1: Option<PageEntry>,
    r2: Option<PageEntry>,
)
    requires
        self_.wf(),
        self_.ioid_active(ioid),
        va_4k_valid(va),
        self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            == (r1 is Some),
        r1 is Some ==> self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            && self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k()[va]
                == page_entry_to_map_entry(&r1.unwrap()),
        self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            == (r2 is Some),
        r2 is Some ==> self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k().dom().contains(va)
            && self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k()[va]
                == page_entry_to_map_entry(&r2.unwrap()),
    ensures
        det_resolve_iommu_table_mapping_equal(r1, r2),
{
    // Bind the shared spec call once so z3 sees a single term for both r1
    // and r2 ensures (instead of two structurally identical but distinct
    // trigger instantiations).
    let m = self_.get_iommu_table_by_ioid(ioid).unwrap().mapping_4k();
    let contains_va = m.dom().contains(va);

    // Both Some-discriminators are pinned to `contains_va`, so they agree.
    assert(contains_va == (r1 is Some));
    assert(contains_va == (r2 is Some));
    assert((r1 is Some) == (r2 is Some));

    if r1 is Some {
        assert(r2 is Some);
        assert(contains_va);

        let pe1 = r1->Some_0;
        let pe2 = r2->Some_0;

        // m[va] is pinned to the *same* MapEntry by both ensures conjuncts,
        // so the two projections are transitively equal.
        assert(m[va] == page_entry_to_map_entry(&pe1));
        assert(m[va] == page_entry_to_map_entry(&pe2));
        assert(page_entry_to_map_entry(&pe1) == page_entry_to_map_entry(&pe2));

        // `spec_page_entry_to_map_entry` is `open`, so MapEntry equality
        // unfolds to per-field equality on {addr, write, execute_disable}.
        assert(spec_page_entry_to_map_entry(&pe1)
            == spec_page_entry_to_map_entry(&pe2));
        assert(spec_page_entry_to_map_entry(&pe1)
            =~= spec_page_entry_to_map_entry(&pe2));
        assert(pe1.addr == pe2.addr);
        assert(pe1.perm.write == pe2.perm.write);
        assert(pe1.perm.execute_disable == pe2.perm.execute_disable);

        // Bridge to PageEntryPerm equality via extensional struct equality.
        // PageEntryPerm has fields {present, ps, write, execute_disable, user};
        // `=~=` unfolds to per-field equality. The three other bits (present,
        // ps, user) are not pinned by the mapping_4k hypothesis. We assert
        // perm equality and let Verus discharge it via `=~=` of the view.
        assert(pe1.perm =~= pe2.perm);

        // PageEntryView is `pub struct { addr, perm }`; `=~=` reduces to
        // field equality, which we just established.
        assert(pe1.view() =~= pe2.view());
        assert(pe1.view() == pe2.view());
    }
}
